import{_ as a,o,c as s,a3 as t}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"65. Compassionate Leave","description":"","frontmatter":{"title":"65. Compassionate Leave","eba":"Nurses and Midwives 2024-2028","topics":["leave","compassionate-leave","preliminary","definitions"]},"headers":[],"relativePath":"ebas/nurses-midwives/leave/65-compassionate-leave.md","filePath":"ebas/nurses-midwives/leave/65-compassionate-leave.md"}'),n={name:"ebas/nurses-midwives/leave/65-compassionate-leave.md"};function r(i,e,p,l,m,c){return o(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="_65-compassionate-leave" tabindex="-1">65. Compassionate Leave <a class="header-anchor" href="#_65-compassionate-leave" aria-label="Permalink to &quot;65. Compassionate Leave&quot;">​</a></h1><p><strong>65.1</strong> An Employer may use its discretion to grant paid and/or unpaid compassionate leave to relatives not covered by the definition of &quot;Immediate family&quot; in <a href="/eba/ebas/allied-health/preliminary/4-definitions.html">clause 4</a>.</p><p><strong>65.2</strong> When Compassionate leave is available</p><p>Compassionate leave may be available under this clause 65 to an Employee for each occasion (a &quot;permissible occasion&quot;) when:</p><p><strong>(a)</strong> the Employee has a miscarriage;</p><p><strong>(b)</strong> the Employee&#39;s current spouse or de facto partner experiences a miscarriage;</p><p><strong>(c)</strong> a member of the Employee&#39;s Immediate family or household:</p><p><strong>(i)</strong> contracts or develops a personal illness or sustains a personal injury that poses a serious threat to their life; or</p><p><strong>(ii)</strong> dies; or</p><p><strong>(d)</strong> a stillborn child is born, where the stillborn child would have been a member of the Employee&#39;s Immediate family, or a member of the Employee&#39;s household, if the stillborn child had been born alive.</p><p><strong>65.3</strong> If the permissible occasion is the contraction or development of a personal illness, or the sustaining of a personal injury, the Employee may take the compassionate leave for that occasion at any time while the illness or injury persists.</p><p><strong>65.4</strong> For the purpose of this clause, miscarriage means the spontaneous loss of an embryo or foetus before 20 weeks of pregnancy, other than where that loss results in a stillborn child.</p><p><strong>65.5</strong> Employees other than casual Employees (applicable from 24 June 2024)</p><p>The provisions of clauses 65.6 to 65.8 apply to all Employees other than casual Employees. The entitlements of casual Employees are set out in clause 65.9.</p><p><strong>65.6</strong> An Employee is entitled to four days&#39; paid leave, on each permissible occasion.</p><p><strong>65.7</strong> An Employee may take compassionate leave for a particular permissible occasion as:</p><p><strong>(a)</strong> a single continuous four-day period;</p><p><strong>(a)</strong> separate periods of at least one day each; or</p><p><strong>(b)</strong> any separate periods to which the Employee and Employer agree.</p><p><strong>65.8</strong> An Employee may take unpaid additional compassionate leave by agreement with the Employer.</p><p><strong>65.9</strong> Casual Employees (applicable from 24 June 2024)</p><p>Subject to the evidence requirements described at clause 65.10, a casual Employee is entitled to four days&#39; unpaid compassionate leave on each permissible occasion. Unpaid compassion leave under this clause may be taken as:</p><p><strong>(a)</strong> a single continuous period;</p><p><strong>(b)</strong> separate periods of at least one day each; or</p><p><strong>(c)</strong> any separate periods to which the Employee and Employer agree.</p><p><strong>65.10</strong> Evidence – all Employees</p><p>Proof of the injury, illness or death must be provided that would satisfy a reasonable person, if requested.</p><p>Plain language terms: bereavement leave, funeral leave, death of family.</p>',28)])])}const u=a(n,[["render",r]]);export{h as __pageData,u as default};
